function rate (crc, vote) {
 $("rateResult").innerHTML = " ";
 $("rateResult").className = "loading";

 new Ajax('get', {
  url: "/ajax.php",
  onSuccess: function(req) {
   var allData  = req.responseJSON;
   var myVote  = allData['myVote'];
   var totScore  = allData['totScore'];
   var totVotes  = allData['totVotes'];
   var avg  = allData['avg'];
   var s   = "";

   s = "Μέσος Όρος : <strong>" + avg + "</strong>

" + totVotes; 
   if (totVotes == 1)
    s += " ψήφος";
   else
    s += " ψήφοι";

   $("rateResult").className = "";
   $("rateResult").innerHTML = s;   
   for (var i = 1; i < 6; i++)
    $("rate"+i).className = "";
   $("rate"+myVote).className = "active";

  },

  onError: function(req) { 
   alert("Error!"); 
  },

  parameters: {
   ajaxAction: "vote",
   voteCrc: crc,
   vote: vote
  }
 }).send();

}

</script> 

